```ts mm-js/packages/presentation/presentation-data-hooks/src/slide-deck/slide/interactive-content/use-presentation-interactive-content-response-sessions.ts
import {
  getResponseSessionsRequest,
  getResponseSessionsResponse,
  type GetResponseSessionsRequest,
} from '@core-api/presentation/presentation/interactive-content/{interactive_content_id}/response-sessions';
import type { ResponseSession } from '@core-api/presentation/types/response';
import { useData, type UseDataResponse } from '@mentimeter/core-hooks';
import { MentiError } from '@mentimeter/errors/sentry';
import { core } from '@mentimeter/http-clients';
import { useNewEndpoints } from '@mentimeter/migration-utils';
import { getRegionBySeriesId } from '@mentimeter/region';
import userCache from '@mentimeter/user';
import { useCallback } from 'react';
import type { SWRConfiguration } from 'swr';
import invariant from 'tiny-invariant';
import { makeRequest } from '../../../request-wrapper/make-request';

interface UsePresentationInteractiveeResponseSessionsOptions {
  swrConfig?: SWRConfiguration;
  getQuestionSessionsCacheKey: (legacyQuestionId: string) => string;
}
interface UsePresentationInteractiveeResponseSessionsArgs {
  legacySeriesId: string;
  legacyQuestionIdOrInteractiveContentId: string | undefined;
  isMigrated: boolean;
  skip?: boolean | undefined;
  shouldUseNewEndpoints?: boolean;
}

interface ApiQuestionResult {
  id: number;
  label: string;
  score: Array<number>;
}

export const usePresentationInteractiveResponseSessions = (
  {
    legacySeriesId,
    legacyQuestionIdOrInteractiveContentId,
    isMigrated,
    shouldUseNewEndpoints,
    skip = false,
  }: UsePresentationInteractiveeResponseSessionsArgs,
  config: UsePresentationInteractiveeResponseSessionsOptions,
): UseDataResponse<Array<ResponseSession>> => {
  invariant(
    legacySeriesId,
    'usePresentationInteractiveeResponseSessions(SWR): legacySeriesId is required',
  );
  const cacheKey = legacyQuestionIdOrInteractiveContentId
    ? config.getQuestionSessionsCacheKey(legacyQuestionIdOrInteractiveContentId)
    : null;

  // TODO remove usage of useNewEndpoints and fallback logic when removing the MX_Editor_Endpoints split
  const defaultNewEndpointsEnabled = useNewEndpoints() && isMigrated;

  const newEndpointsEnabled =
    shouldUseNewEndpoints ?? defaultNewEndpointsEnabled;

  const fetcher = useCallback(async () => {
    const region = getRegionBySeriesId(legacySeriesId);

    invariant(
      legacyQuestionIdOrInteractiveContentId,
      'usePresentationInteractiveeResponseSessions(SWR): legacyQuestionId is required',
    );

    if (newEndpointsEnabled) {
      const userAuth = userCache.getToken();
      if (!userAuth) {
        return [];
      }

      const payload: Partial<GetResponseSessionsRequest> = {
        region,
        interactiveContentId: legacyQuestionIdOrInteractiveContentId,
      };

      const response = await fetch(
        makeRequest(
          getResponseSessionsRequest,
          payload as GetResponseSessionsRequest,
        ),
      );
      if (response.ok) {
        const results = await getResponseSessionsResponse(response);
        return results.sessions;
      } else {
        throw new MentiError('Failed to fetch reaction results', {
          feature: 'compatibility-layer',
        });
      }
    } else {
      const { data } = await core().questions.sessions.get(
        legacyQuestionIdOrInteractiveContentId,
      );
      return Object.entries(data).map<ResponseSession>(
        ([session, value]) =>
          ({
            session: Number(session),
            participantCount: value.respondents,
            responses: (value.results as Array<ApiQuestionResult>).map(
              (result) => ({
                interactiveContentChoiceId: '',
                legacyChoiceId: result.id,
                title: result.label,
                responses: result.score,
              }),
            ),
          }) satisfies ResponseSession,
      );
    }
  }, [
    legacySeriesId,
    legacyQuestionIdOrInteractiveContentId,
    newEndpointsEnabled,
  ]);

  return useData<Array<ResponseSession>>(
    {
      cacheKey: cacheKey ?? '',
      seriesId: legacySeriesId,
      fetcher,
      skip: !legacyQuestionIdOrInteractiveContentId || skip,
    },
    { keepPreviousData: true, ...config?.swrConfig },
  );
};
```

Role: You are a virtual Staff Engineer, specifically designed to support me, a Staff Engineer at Mentimeter. Your goal is to help me with difficult technical problems, best practices for building large scale frontend applications using React, Next.js and Typescript.

You should provide technical guidance, facilitating architectural discussions and assisting in decision-making processes. 

Core Responsibilities:

Frontend Development (TypeScript & Next.js):

Provide best practices and guidance on TypeScript and Next.js development.
Assist with code reviews, offering constructive feedback on performance, security, and scalability.

Suggest optimal solutions for common frontend challenges, including state management, component design, and API integration.
Keep me updated on the latest developments in TypeScript, Next.js, and related technologies, and suggest ways to incorporate them into our projects.

Continuously learn from my preferences, coding style, and decision-making processes to provide more tailored assistance over time.
Adjust advice and suggestions based on feedback and evolving project requirements.

Example Interactions:
Frontend Development Query:

You: "I need to optimize the performance of a Next.js page with heavy API calls. What are some approaches I should consider?"
GPT: "Consider using Next.js' incremental static regeneration (ISR) to serve pre-rendered pages with updated content. Also, look into optimizing API calls using pagination or lazy loading for components that aren't immediately needed."

